package com.bmstu.iu3.automanagement

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Build
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.colorResource
import androidx.compose.ui.text.font.Font
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import androidx.navigation.compose.rememberNavController
import com.bmstu.iu3.automanagement.R.font.game_font
import com.bmstu.iu3.automanagement.R.font.press_start2p
import com.bmstu.iu3.automanagement.models.MainViewModel
import com.bmstu.iu3.automanagement.ui.navigation.SetupNavGraph
import com.bmstu.iu3.automanagement.ui.theme.AutoManagementTheme
import com.bmstu.iu3.automanagement.utils.DevMenuDialog

class MainActivity : ComponentActivity() {
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            val mainViewModel: MainViewModel = viewModel()
            val budgetText = mainViewModel.getBudgetDisplay()

            var showDevMenu by remember { mutableStateOf(false) }

            AutoManagementTheme {
                Surface(
                    modifier = Modifier.fillMaxSize(),
                    color = colorResource(id = R.color.black)
                ) {
                    val navController = rememberNavController()
                    Scaffold(
                        modifier = Modifier.fillMaxSize(),
                        containerColor = MaterialTheme.colorScheme.surface,
                        topBar = {
                            TopAppBar(
                                title = { Text("Auto Management", fontFamily = FontFamily(Font(game_font))) },
                                actions = {
                                    IconButton(onClick = { showDevMenu = true }) {
                                        Icon(
                                            Icons.Default.Build, 
                                            contentDescription = "Dev Menu", 
                                            tint = MaterialTheme.colorScheme.secondary
                                        )
                                    }

                                    Text(
                                        text = budgetText,
                                        modifier = Modifier.padding(end = 16.dp),
                                        style = MaterialTheme.typography.titleMedium,
                                        color = MaterialTheme.colorScheme.primary,
                                        fontFamily = FontFamily(Font(press_start2p))
                                    )
                                },
                                colors = TopAppBarDefaults.topAppBarColors(
                                    containerColor = MaterialTheme.colorScheme.background,
                                    titleContentColor = MaterialTheme.colorScheme.onBackground
                                )
                            )
                        }
                    ) { innerPadding ->
                        Box(modifier = Modifier.padding(innerPadding)) {
                            SetupNavGraph(
                                navController = navController,
                                onExit = { finish() }
                            )
                        }
                    }

                    if (showDevMenu) {
                        DevMenuDialog(onDismiss = { showDevMenu = false })
                    }
                }
            }
        }
    }
}

package com.bmstu.iu3.automanagement

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Build
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.compose.ui.res.colorResource
import androidx.compose.ui.text.font.Font
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import androidx.navigation.compose.rememberNavController
import com.bmstu.iu3.automanagement.R.font.game_font
import com.bmstu.iu3.automanagement.R.font.press_start2p
import com.bmstu.iu3.automanagement.data.GameState
import com.bmstu.iu3.automanagement.data.GameSaveManager
import com.bmstu.iu3.automanagement.models.MainViewModel
import com.bmstu.iu3.automanagement.ui.navigation.SetupNavGraph
import com.bmstu.iu3.automanagement.ui.theme.AutoManagementTheme
import com.bmstu.iu3.automanagement.utils.DevMenuDialog

class MainActivity : ComponentActivity() {
    @OptIn(ExperimentalMaterial3Api::class)
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            val mainViewModel: MainViewModel = viewModel()
            val budgetText = mainViewModel.getBudgetDisplay()
            val saveManager = GameSaveManager(this@MainActivity)

            var showDevMenu by remember { mutableStateOf(false) }

            AutoManagementTheme {
                Surface(
                    modifier = Modifier.fillMaxSize(),
                    color = colorResource(id = R.color.black)
                ) {
                    val navController = rememberNavController()
                    Scaffold(
                        modifier = Modifier.fillMaxSize(),
                        containerColor = MaterialTheme.colorScheme.surface,
                        topBar = {
                            TopAppBar(
                                title = {
                                    Column {
                                        Text("Auto Management", fontFamily = FontFamily(Font(game_font)))
                                        if (GameState.getCurrentPlayer().isNotEmpty()) {
                                            Text(
                                                "Player: ${GameState.getCurrentPlayer()}",
                                                style = MaterialTheme.typography.labelSmall
                                            )
                                        }
                                    }
                                },
                                actions = {
                                    IconButton(onClick = { showDevMenu = true }) {
                                        Icon(
                                            Icons.Default.Build, 
                                            contentDescription = "Dev Menu", 
                                            tint = MaterialTheme.colorScheme.secondary
                                        )
                                    }

                                    Text(
                                        text = budgetText,
                                        modifier = Modifier.padding(end = 16.dp),
                                        style = MaterialTheme.typography.titleMedium,
                                        color = MaterialTheme.colorScheme.primary,
                                        fontFamily = FontFamily(Font(press_start2p))
                                    )
                                },
                                colors = TopAppBarDefaults.topAppBarColors(
                                    containerColor = MaterialTheme.colorScheme.background,
                                    titleContentColor = MaterialTheme.colorScheme.onBackground
                                )
                            )
                        }
                    ) { innerPadding ->
                        Box(modifier = Modifier.padding(innerPadding)) {
                            SetupNavGraph(
                                navController = navController,
                                onExit = { finish() },
                                saveManager = saveManager
                            )
                        }
                    }

                    if (showDevMenu) {
                        DevMenuDialog(onDismiss = { showDevMenu = false })
                    }
                }
            }
        }
    }
}

package com.bmstu.iu3.automanagement.models

class Car {
    private var name: String = ""
    private var engine: Engine? = null
    private var gearbox: Gearbox? = null
    private var chassis: Chassis? = null
    private var suspension: Suspension? = null
    private var aerodynamics: Aerodynamics? = null
    private var tyres: Tyres? = null
    private var performance: Double = 0.0

    fun getName(): String = name
    fun setName(value: String) { name = value }

    fun getEngine(): Engine? = engine
    fun setEngine(value: Engine?) { engine = value }

    fun getGearbox(): Gearbox? = gearbox
    fun setGearbox(value: Gearbox?) { gearbox = value }

    fun getChassis(): Chassis? = chassis
    fun setChassis(value: Chassis?) { chassis = value }

    fun getSuspension(): Suspension? = suspension
    fun setSuspension(value: Suspension?) { suspension = value }

    fun getAerodynamics(): Aerodynamics? = aerodynamics
    fun setAerodynamics(value: Aerodynamics?) { aerodynamics = value }

    fun getTyres(): Tyres? = tyres
    fun setTyres(value: Tyres?) { tyres = value }

    fun getPerformance(): Double = performance
    fun setPerformance(value: Double) { performance = value }

    fun isComplete(): Boolean {
        return engine != null && gearbox != null && chassis != null && 
               suspension != null && aerodynamics != null && tyres != null
    }

    fun getTotalPerformance(): Double {
        var total = 0.0
        total += engine?.getPerformance() ?: 0.0
        total += gearbox?.getPerformance() ?: 0.0
        total += chassis?.getPerformance() ?: 0.0
        total += suspension?.getPerformance() ?: 0.0
        total += aerodynamics?.getPerformance() ?: 0.0
        total += tyres?.getPerformance() ?: 0.0
        return total
    }
}

package com.bmstu.iu3.automanagement.models

class Car {
    private var name: String = ""
    private var engine: Engine? = null
    private var gearbox: Gearbox? = null
    private var chassis: Chassis? = null
    private var suspension: Suspension? = null
    private var aerodynamics: Aerodynamics? = null
    private var tyres: Tyres? = null
    private var meleeWeapon1: MeleeWeapon? = null
    private var meleeWeapon2: MeleeWeapon? = null
    private var rangedWeapon: RangedWeapon? = null
    private var performance: Double = 0.0

    fun getName(): String = name
    fun setName(value: String) { name = value }

    fun getEngine(): Engine? = engine
    fun setEngine(value: Engine?) { engine = value }

    fun getGearbox(): Gearbox? = gearbox
    fun setGearbox(value: Gearbox?) { gearbox = value }

    fun getChassis(): Chassis? = chassis
    fun setChassis(value: Chassis?) { chassis = value }

    fun getSuspension(): Suspension? = suspension
    fun setSuspension(value: Suspension?) { suspension = value }

    fun getAerodynamics(): Aerodynamics? = aerodynamics
    fun setAerodynamics(value: Aerodynamics?) { aerodynamics = value }

    fun getTyres(): Tyres? = tyres
    fun setTyres(value: Tyres?) { tyres = value }

    fun getMeleeWeapon1(): MeleeWeapon? = meleeWeapon1
    fun setMeleeWeapon1(value: MeleeWeapon?) { meleeWeapon1 = value }

    fun getMeleeWeapon2(): MeleeWeapon? = meleeWeapon2
    fun setMeleeWeapon2(value: MeleeWeapon?) { meleeWeapon2 = value }

    fun getRangedWeapon(): RangedWeapon? = rangedWeapon
    fun setRangedWeapon(value: RangedWeapon?) { rangedWeapon = value }
    
    fun getPerformance(): Double = performance
    fun setPerformance(value: Double) { performance = value }

    fun isComplete(): Boolean {
        return engine != null && gearbox != null && chassis != null && 
               suspension != null && aerodynamics != null && tyres != null
    }

    fun getTotalPerformance(): Double {
        var total = 0.0
        total += engine?.getPerformance() ?: 0.0
        total += gearbox?.getPerformance() ?: 0.0
        total += chassis?.getPerformance() ?: 0.0
        total += suspension?.getPerformance() ?: 0.0
        total += aerodynamics?.getPerformance() ?: 0.0
        total += tyres?.getPerformance() ?: 0.0
        return total
    }

    fun getAllInstalledComponents(): List<Component> {
        return listOfNotNull(
            engine,
            gearbox,
            chassis,
            suspension,
            aerodynamics,
            tyres,
            meleeWeapon1,
            meleeWeapon2,
            rangedWeapon
        )
    }
}

package com.bmstu.iu3.automanagement.models

import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableDoubleStateOf
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue

sealed class Component {
    private var id: String = ""
    private var name: String = ""
    private var price: Double = 0.0
    private var performance: Double = 0.0

    // Используем State для реактивности в Compose
    private var wearState = mutableDoubleStateOf(0.0)
    private var isDestroyedState = mutableStateOf(false)

    fun getId(): String = id
    fun setId(value: String) { id = value }
    fun getName(): String = name
    fun setName(value: String) { name = value }
    fun getPrice(): Double = price
    fun setPrice(value: Double) { price = value }

    fun getWear(): Double = wearState.doubleValue
    fun setWear(value: Double) { wearState.doubleValue = value }

    fun getPerformance(): Double = performance
    fun setPerformance(value: Double) { performance = value }

    fun isDestroyed(): Boolean = isDestroyedState.value
    fun setDestroyed(value: Boolean) { isDestroyedState.value = value }
}

class Engine : Component() {
    private var power: Int = 0
    private var weight: Int = 0
    private var type: String = ""
    fun getPower(): Int = power
    fun setPower(value: Int) { power = value }
    fun getWeight(): Int = weight
    fun setWeight(value: Int) { weight = value }
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Gearbox : Component() {
    private var gears: Int = 0
    private var type: String = ""
    fun getGears(): Int = gears
    fun setGears(value: Int) { gears = value }
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Chassis : Component() {
    private var maxEngineWeight: Int = 0
    private var suspensionType: String = ""
    fun getMaxEngineWeight(): Int = maxEngineWeight
    fun setMaxEngineWeight(value: Int) { maxEngineWeight = value }
    fun getSuspensionType(): String = suspensionType
    fun setSuspensionType(value: String) { suspensionType = value }
}

class Suspension : Component() {
    private var type: String = ""
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Aerodynamics : Component()

class Tyres : Component() {
    private var grip: Double = 0.0
    fun getGrip(): Double = grip
    fun setGrip(value: Double) { grip = value }
}

package com.bmstu.iu3.automanagement.models

import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableDoubleStateOf
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue

sealed class Component {
    private var id: String = ""
    private var name: String = ""
    private var price: Double = 0.0
    private var performance: Double = 0.0

    // Используем State для реактивности в Compose
    private var wearState = mutableDoubleStateOf(0.0)
    private var isDestroyedState = mutableStateOf(false)

    fun getId(): String = id
    fun setId(value: String) { id = value }
    fun getName(): String = name
    fun setName(value: String) { name = value }
    fun getPrice(): Double = price
    fun setPrice(value: Double) { price = value }

    fun getWear(): Double = wearState.doubleValue
    fun setWear(value: Double) { wearState.doubleValue = value }

    fun getPerformance(): Double = performance
    fun setPerformance(value: Double) { performance = value }

    fun isDestroyed(): Boolean = isDestroyedState.value
    fun setDestroyed(value: Boolean) { isDestroyedState.value = value }
}

class Engine : Component() {
    private var power: Int = 0
    private var weight: Int = 0
    private var type: String = ""
    fun getPower(): Int = power
    fun setPower(value: Int) { power = value }
    fun getWeight(): Int = weight
    fun setWeight(value: Int) { weight = value }
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Gearbox : Component() {
    private var gears: Int = 0
    private var type: String = ""
    fun getGears(): Int = gears
    fun setGears(value: Int) { gears = value }
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Chassis : Component() {
    private var maxEngineWeight: Int = 0
    private var suspensionType: String = ""
    fun getMaxEngineWeight(): Int = maxEngineWeight
    fun setMaxEngineWeight(value: Int) { maxEngineWeight = value }
    fun getSuspensionType(): String = suspensionType
    fun setSuspensionType(value: String) { suspensionType = value }
}

class Suspension : Component() {
    private var type: String = ""
    fun getType(): String = type
    fun setType(value: String) { type = value }
}

class Aerodynamics : Component()

class Tyres : Component() {
    private var grip: Double = 0.0
    fun getGrip(): Double = grip
    fun setGrip(value: Double) { grip = value }
}

abstract class Weapon : Component() {
    private var weight: Int = 0
    private var accuracy: Double = 0.0

    fun getWeight(): Int = weight
    fun setWeight(value: Int) { weight = value }

    fun getAccuracy(): Double = accuracy
    fun setAccuracy(value: Double) { accuracy = value }
}

class MeleeWeapon : Weapon() {
    private var impact: Int = 0

    fun getImpact(): Int = impact
    fun setImpact(value: Int) { impact = value }
}

class RangedWeapon : Weapon() {
    private var range: Int = 0

    fun getRange(): Int = range
    fun setRange(value: Int) { range = value }
}

